-- >>>>>>>>>>>>>>>>>>>>  tables/00_admin_config.sql  <<<<<<<<<<<<<<<<<<<<

-- ============================================================
-- Admin config: tier subscription + tax settings
-- Created FIRST — seller_profiles.tier and order snapshots FK / read from here.
-- ============================================================

create table public.admin_tier_config (
  tier            text    not null,
  commission_rate numeric not null,
  monthly_fee_usd numeric not null default 0,
  max_items       integer,      -- null = unlimited
  max_categories  integer,      -- null = unlimited
  constraint admin_tier_config_pkey primary key (tier)
);

insert into public.admin_tier_config (tier, commission_rate, monthly_fee_usd, max_items, max_categories)
values
  ('founding',   0,    0,  null, null),  -- 0% commission, early adopter sellers
  ('community',  0.19, 0,  3,    1),
  ('tindahan',   0.17, 29, 30,   5),
  ('negosyo',    0.15, 49, 90,   10),
  ('enterprise', 0.13, 89, null, null),
  ('bodega',     0,    0,  null, null)   -- negotiated: rate set via seller_profiles.commission_rate_override
on conflict (tier) do nothing;

comment on table public.admin_tier_config is
  'Source of truth for tier definitions. Changing commission_rate here does NOT affect past orders.';
comment on column public.admin_tier_config.commission_rate is
  'Default rate for this tier. Bodega = 0 because rate is negotiated per seller.';


create table public.admin_tax_config (
  key         text        not null,
  rate        numeric     not null,
  description text,
  updated_at  timestamptz not null default now(),
  constraint admin_tax_config_pkey primary key (key)
);

insert into public.admin_tax_config (key, rate, description)
values
  ('vat_rate',                   0.10,        'VAT on Sariko commission (platform service fee to sellers)'),
  ('withholding_rate_goods',     0.01,        'Withholding tax for goods sellers (imported products, dry goods)'),
  ('withholding_rate_services',  0.02,        'Withholding tax for service sellers (food, tutoring, tailoring)'),
  ('annual_revenue_threshold',   100000000,   'Annual VND threshold above which withholding tax applies')
on conflict (key) do nothing;

comment on table public.admin_tax_config is
  'Platform-wide tax settings. Adjustable by admin. Changes apply to new orders only.';


-- >>>>>>>>>>>>>>>>>>>>  tables/01_users.sql  <<<<<<<<<<<<<<<<<<<<

-- ============================================================
-- Users + user addresses
-- public.users.id mirrors auth.users.id (populated by the handle_user_create
-- trigger in functions/functions.sql).
-- ============================================================

create table public.users (
  id uuid not null default gen_random_uuid (),
  email text not null,
  name text null,
  phone text null,
  role text null default 'customer'::text,
  created_at timestamp without time zone null default now(),
  is_seller boolean null default false,
  updated_at timestamp without time zone null default now(),
  avatar_url text null,
  preferred_language text null,
  constraint users_pkey primary key (id),
  constraint users_email_key unique (email),
  constraint users_role_check check (
    (role = any (array['customer'::text, 'seller'::text]))
  )
) TABLESPACE pg_default;


create table public.user_addresses (
  id bigint generated by default as identity not null,
  user_id uuid not null,
  label text null,
  address text not null,
  lat double precision null,
  lon double precision null,
  is_default boolean not null default false,
  created_at timestamp with time zone not null default now(),
  constraint user_addresses_pkey primary key (id),
  constraint user_addresses_user_id_fkey foreign KEY (user_id) references users (id) on update CASCADE on delete CASCADE
) TABLESPACE pg_default;


-- >>>>>>>>>>>>>>>>>>>>  tables/02_seller_profiles.sql  <<<<<<<<<<<<<<<<<<<<

-- ============================================================
-- Seller profiles
-- tier FK → admin_tier_config; status coming_soon | active.
-- ============================================================

create table public.seller_profiles (
  id uuid not null default gen_random_uuid (),
  user_id uuid null,
  store_name text not null,
  description text null,
  avatar_url text null,
  cover_url text null,
  address text null,
  lat numeric null,
  lon numeric null,
  is_open boolean null default true,
  opening_time time without time zone null,
  closing_time time without time zone null,
  is_verified boolean null default false,
  created_at timestamp without time zone null default now(),
  slug text not null,
  phone text null,
  tier text not null default 'community'::text,
  commission_rate_override numeric null,
  bank_account_number text null,
  bank_name text null,
  bank_account_holder text null,
  tax_category text not null default 'services'::text,
  status text not null default 'coming_soon'::text,
  constraint seller_profiles_pkey primary key (id),
  constraint seller_profiles_slug_key unique (slug),
  constraint seller_profiles_tier_fkey foreign KEY (tier) references admin_tier_config (tier),
  constraint seller_profiles_user_id_fkey foreign KEY (user_id) references users (id) on delete CASCADE,
  constraint seller_profiles_tax_category_check check (
    (tax_category = any (array['goods'::text, 'services'::text]))
  ),
  constraint seller_profiles_status_check check (
    (status = any (array['coming_soon'::text, 'active'::text]))
  )
) TABLESPACE pg_default;

create index IF not exists idx_seller_location on public.seller_profiles using btree (lat, lon) TABLESPACE pg_default;

comment on column public.seller_profiles.commission_rate_override is
  'Only set for bodega tier. NULL = use admin_tier_config.commission_rate.';


