-- >>>>>>>>>>>>>>>>>>>>  tables/09_refunds.sql  <<<<<<<<<<<<<<<<<<<<

-- ============================================================
-- Refunds (VNPay refund tracking) — created before payments (payments.refund_id FK).
-- ============================================================

create table public.refunds (
