-- >>>>>>>>>>>>>>>>>>>>  tables/10_payments.sql  <<<<<<<<<<<<<<<<<<<<

-- ============================================================
-- Payments (VNPay charge / refund records)
-- ============================================================

create table public.payments (
  id uuid not null default gen_random_uuid (),
